from cryptography.fernet import Fernet
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2
from cryptography.hazmat.backends import default_backend
import base64
import hashlib
import json

# Data Classification Constants
DATA_CLASSIFICATION = {
 'PUBLIC': {'encryption': 'none', 'retention_days': 30},
 'INTERNAL': {'encryption': 'AES-128', 'retention_days': 90},
 'CONFIDENTIAL': {'encryption': 'AES-256', 'retention_days': 365},
 'RESTRICTED': {'encryption': 'AES-256', 'retention_days': 2555}
}

class CloudDataProtection:
 """Implements data protection strategies for cloud environments"""

 def __init__(self, classification='CONFIDENTIAL'):
 self.classification = classification
 self.encryption_level = DATA_CLASSIFICATION[classification]['encryption']

 def derive_key(self, password: str, salt: bytes) -> bytes:
 """Derive encryption key using PBKDF2 - Key Management best practice"""
 kdf = PBKDF2(
 algorithm=hashes.SHA256(),
 length=32,
 salt=salt,
 iterations=100000,
 backend=default_backend()
 )
 return base64.urlsafe_b64encode(kdf.derive(password.encode()))

 def encrypt_data(self, plaintext: str, password: str) -> dict:
 """Encrypt data at rest using AES-256"""
 if self.encryption_level == 'none':
 return {'encrypted': False, 'data': plaintext}

 # Generate random salt for key derivation
 salt = Fernet.generate_key()[:16]
 key = self.derive_key(password, salt)
 cipher = Fernet(key)

 # Encrypt the data
 ciphertext = cipher.encrypt(plaintext.encode())

 return {
 'encrypted': True,
 'ciphertext': base64.b64encode(ciphertext).decode(),
 'salt': base64.b64encode(salt).decode(),
 'algorithm': 'AES-256',
 'classification': self.classification
 }

 def decrypt_data(self, encrypted_data: dict, password: str) -> str:
 """Decrypt data with proper key management"""
 if not encrypted_data.get('encrypted'):
 return encrypted_data['data']

 salt = base64.b64decode(encrypted_data['salt'])
 key = self.derive_key(password, salt)
 cipher = Fernet(key)

 ciphertext = base64.b64decode(encrypted_data['ciphertext'])
 return cipher.decrypt(ciphertext).decode()

 @staticmethod
 def encrypt_in_transit(data: bytes) -> bytes:
 """Simulate TLS encryption for data in transit"""
 # In production, use TLS 1.2+ via SSL/TLS libraries
 hash_value = hashlib.sha256(data).digest()
 return base64.b64encode(data) + b'.hash.' + base64.b64encode(hash_value)

# Data Loss Prevention (DLP) Example
class DLPValidator:
 """Data Loss Prevention - detects sensitive data patterns"""

 SENSITIVE_PATTERNS = {
 'credit_card': r'\b\d{4}[- ]?\d{4}[- ]?\d{4}[- ]?\d{4}\b',
 'ssn': r'\b\d{3}[- ]?\d{2}[- ]?\d{4}\b',
 'email': r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
 'api_key': r'\b[A-Za-z0-9]{32,}\b'
 }

 def __init__(self):
 import re
 self.patterns = {k: re.compile(v) for k, v in self.SENSITIVE_PATTERNS.items()}

 def scan_data(self, data: str) -> dict:
 """Scan for sensitive data and classify risk"""
 findings = {}
 for ptype, pattern in self.patterns.items():
 matches = pattern.findall(data)
 if matches:
 findings[ptype] = {
 'count': len(matches),
 'action': 'BLOCK',
 'severity': 'HIGH'
 }
 return {
 'compliant': len(findings) == 0,
 'findings': findings,
 'recommendation': 'Apply encryption or tokenization' if findings else 'Allow'
 }

# Demo Usage
if __name__ == "__main__":
 # Example: Protect CONFIDENTIAL data with encryption at rest
