import json
import hashlib
from datetime import datetime, timedelta
from collections import defaultdict
from enum import Enum

class ThreatSeverity(Enum):
 LOW = 1
 MEDIUM = 2
 HIGH = 3
 CRITICAL = 4

class SecurityEvent:
 """Represents a security event from cloud services"""
 def __init__(self, event_id, source, event_type, timestamp, details):
 self.event_id = event_id
 self.source = source
 self.event_type = event_type
 self.timestamp = timestamp
 self.details = details
 self.severity = ThreatSeverity.LOW

class SIEMSystem:
 """Security Information and Event Management system for cloud monitoring"""

 # Known attack patterns for IDS/IPS detection
 ATTACK_PATTERNS = {
 'brute_force': ['failed_login', 'authentication_failure'],
 'privilege_escalation': ['sudo', 'admin_access', 'role_change'],
 'data_exfiltration': ['large_download', 'bulk_transfer', 'unusual_outbound'],
 'sql_injection': ['" OR "', "' OR '", '1=1', 'UNION SELECT'],
 'xss_attack': ['<script>', 'javascript:', 'onerror=']
 }

 def __init__(self):
 self.events = []
 self.alerts = []
 self.baseline = defaultdict(int)
 self.threat_rules = self._initialize_threat_rules()

 def _initialize_threat_rules(self):
 """Configure detection rules for different threat types"""
 return {
 'multiple_failed_logins': {
 'condition': lambda e: e.event_type == 'failed_login',
 'threshold': 5,
 'window_minutes': 10,
 'severity': ThreatSeverity.HIGH
 },
 'admin_access_unusual_time': {
 'condition': lambda e: e.event_type == 'admin_access',
 'hour_range': (0, 6), # Unusual hours
 'severity': ThreatSeverity.CRITICAL
 },
 'large_data_transfer': {
 'condition': lambda e: 'size' in e.details,
 'threshold_mb': 100,
 'severity': ThreatSeverity.MEDIUM
 },
 'suspicious_ip_access': {
 'condition': lambda e: e.details.get('ip') in ['0.0.0.0', '192.168.1.1'],
 'severity': ThreatSeverity.HIGH
 }
 }

 def ingest_log(self, event: SecurityEvent):
 """Ingest logs from cloud services (simulates CloudTrail, GuardDuty)"""
 self.events.append(event)
 self._detect_threats(event)
 self._update_baseline(event)

 def _update_baseline(self, event: SecurityEvent):
 """Build behavioral baseline for anomaly detection"""
 key = f"{event.source}:{event.event_type}"
 self.baseline[key] += 1

 def _detect_threats(self, event: SecurityEvent):
 """IDS/IPS: Detect threats using pattern matching and rules"""
 # Check attack patterns
 for attack_type, patterns in self.ATTACK_PATTERNS.items():
 for pattern in patterns:
 if pattern.lower() in str(event.details).lower():
 self._create_alert(event, attack_type, ThreatSeverity.CRITICAL)
 return

 # Check configured threat rules
 for rule_name, rule in self.threat_rules.items():
 if rule['condition'](event):
 # For threshold-based rules, check rate
 if 'threshold' in rule:
 recent_count = self._count_recent_events(
 event.event_type, 
 rule.get('window_minutes', 10)
 )
 if recent_count >= rule['threshold']:
 self._create_alert(event, rule_name, rule['severity'])
 else:
 self._create_alert(event, rule_name, rule['severity'])

 def _count_recent_events(self, event_type: str, window_minutes: int) -> int:
 """Count events of a type within time window"""
 cutoff = datetime.now() - timedelta(minutes=window_minutes)
 return sum(1 for e in self.events 
 if e.event_type == event_type and e.timestamp > cutoff)

 def _create_alert(self, event: SecurityEvent, threat_type: str, severity: ThreatSeverity):
 """Generate automated security alert"""
 alert = {
 'alert_id': hashlib.md5(f"{event.event_id}{threat_type}".encode()).hexdigest(),
 'timestamp': datetime.now().isoformat(),
 'threat_type': threat_type,
 'severity': severity.name,
 'source_event': event.event_id,
 'source': event.source,
 'action_required': self._get_action(severity)
 }
 event.severity = severity
 self.alerts.append(alert)
 print(f"[ALERT {severity.name}] {threat_type} detected from {event.source}")

 def _get_action(self, severity: ThreatSeverity) -> str:
 """Determine response action based on severity"""
 actions = {
 ThreatSeverity.LOW: "Log and monitor",
 ThreatSeverity.MEDIUM: "Notify security team",
 ThreatSeverity.HIGH: "Immediate investigation required",
 ThreatSeverity.CRITICAL: "Auto-block and incident response"
 }
 return actions.get(severity, "Unknown")

 def get_high_severity_alerts(self):
 """Get all high/critical alerts for security team review"""
 return [a for a in self.alerts 
 if a['severity'] in ['HIGH', 'CRITICAL']]

 def generate_security_report(self) -> dict:
 """Generate security summary for audit and compliance"""
 return {
 'total_events': len(self.events),
 'total_alerts': len(self.alerts),
 'severity_breakdown': self._count_by_severity(),
 'top_threats': self._get_top_threats(),
 'recommendations': self._generate_recommendations()
 }

 def _count_by_severity(self) -> dict:
 counts = defaultdict(int)
 for alert in self.alerts:
 counts[alert['severity']] += 1
 return dict(counts)

 def _get_top_threats(self) -> list:
 threat_counts = defaultdict(int)
 for alert in self.alerts:
 threat_counts[alert['threat_type']] += 1
 return sorted(threat_counts.items(), key=lambda x: x[1], reverse=True)[:5]

 def _generate_recommendations(self) -> list:
 """Generate security recommendations based on detected threats"""
 recommendations = []
 critical_count = len([a for a in self.alerts if a['severity'] == 'CRITICAL'])

 if critical_count > 0:
 recommendations.append("CRITICAL: Review and block malicious IPs immediately")

 if self.baseline.get('login:failed_login', 0) > 10:
 recommendations.append("Implement account lockout policy and MFA enforcement")

 recommendations.append("Review and update security group rules")
 recommendations.append("Ensure all data transfers are encrypted in transit")

 return recommendations

