import json
import re
from enum import Enum
from typing import List, Dict, Set

class Effect(Enum):
 ALLOW = "Allow"
 DENY = "Deny"

class ResourceType(Enum):
 EC2 = "ec2:*"
 S3 = "s3:*"
 RDS = "rds:*"
 LAMBDA = "lambda:*"
 IAM = "iam:*"

class IAMPolicy:
 """Represents an IAM policy with RBAC and least privilege enforcement"""

 def __init__(self, policy_name: str):
 self.policy_name = policy_name
 self.version = "2012-10-17"
 self.statements = []

 def add_statement(self, sid: str, effect: Effect, actions: List[str], 
 resources: List[str], conditions: Dict = None):
 """Add a policy statement with optional conditions"""
 statement = {
 "Sid": sid,
 "Effect": effect.value,
 "Action": actions,
 "Resource": resources,
 }
 if conditions:
 statement["Condition"] = conditions
 self.statements.append(statement)

 def to_json(self) -> str:
 """Export policy as JSON for AWS/Azure IAM"""
 policy = {
 "Version": self.version,
 "Statement": self.statements
 }
 return json.dumps(policy, indent=2)

class RBACManager:
 """Role-Based Access Control manager for cloud IAM"""

 # Predefined roles with permissions
 ROLE_PERMISSIONS = {
 'admin': ['*'],
 'developer': [
 'ec2:Describe*', 'ec2:Start*', 'ec2:Stop*',
 's3:GetObject', 's3:PutObject', 's3:ListBucket',
 'lambda:InvokeFunction', 'lambda:GetFunction',
 'cloudwatch:GetMetricStatistics', 'logs:Describe*'
 ],
 'analyst': [
 's3:GetObject', 's3:ListBucket',
 'cloudwatch:GetMetricStatistics',
 'dynamodb:Scan', 'dynamodb:Query'
 ],
 'auditor': [
 'cloudtrail:LookupEvents',
 'cloudwatch:Describe*',
 'config:DescribeConfigurationRecorders',
 's3:GetObject'
 ],
 'network_admin': [
 'ec2:Describe*', 'ec2:CreateNetworkInterface',
 'elasticloadbalancing:*', 'vpc:*'
 ]
 }

 def __init__(self):
 self.user_roles = {}
 self.user_permissions = {}

 def assign_role(self, user_id: str, role: str):
 """Assign a role to a user based on job function"""
 if role not in self.ROLE_PERMISSIONS:
 raise ValueError(f"Unknown role: {role}")

 if user_id not in self.user_roles:
 self.user_roles[user_id] = []

 if role not in self.user_roles[user_id]:
 self.user_roles[user_id].append(role)
 self._recalculate_permissions(user_id)

 def _recalculate_permissions(self, user_id: str):
 """Combine permissions from all assigned roles (least privilege)"""
 all_permissions = set()
 for role in self.user_roles.get(user_id, []):
 all_permissions.update(self.ROLE_PERMISSIONS.get(role, []))
 self.user_permissions[user_id] = list(all_permissions)

 def get_permissions(self, user_id: str) -> List[str]:
 """Get effective permissions for a user"""
 return self.user_permissions.get(user_id, [])

 def check_permission(self, user_id: str, required_action: str) -> bool:
 """Check if user has specific permission (supports wildcards)"""
 user_perms = self.get_permissions(user_id)

 for perm in user_perms:
 # Handle wildcard permissions
 if perm == '*':
 return True
 # Check exact match or prefix match
 if perm == required_action or perm.rstrip('*') in required_action:
 return True
 # Handle action:* patterns
 if perm.endswith(':*'):
 prefix = perm[:-1]
 if required_action.startswith(prefix):
 return True

 return False

class LeastPrivilegeValidator:
 """Validates IAM policies against least privilege principle"""

 def __init__(self):
 self.warnings = []
 self.errors = []

 def validate_policy(self, policy: IAMPolicy) -> Dict:
 """Analyze policy for security issues"""
 self.warnings = []
 self.errors = []

 for stmt in policy.statements:
 self._check_wildcard_actions(stmt)
 self._check_wildcard_resources(stmt)
 self._check_missing_conditions(stmt)
 self._check_deny_absence(stmt)

 return {
 'valid': len(self.errors) == 0,
 'warnings': self.warnings,
 'errors': self.errors,
 'score': self._calculate_score()
 }

 def _check_wildcard_actions(self, stmt: Dict):
 """Warn about wildcard (*) actions - violates least privilege"""
 actions = stmt.get('Action', [])
 if '*' in actions:
 self.errors.append(
 f"Statement {stmt['Sid']}: Wildcard action '*' violates least privilege"
 )

 def _check_wildcard_resources(self, stmt: Dict):
 """Warn about wildcard resources"""
 resources = stmt.get('Resource', [])
 if '*' in resources:
 self.warnings.append(
 f"Statement {stmt['Sid']}: Wildcard resource - consider limiting scope"
 )

 def _check_missing_conditions(self, stmt: Dict):
 """Recommend conditions for additional security"""
 if 'Condition' not in stmt and stmt.get('Effect') == 'Allow':
 self.warnings.append(
 f"Statement {stmt['Sid']}: No conditions - add IP or time conditions"
 )

 def _check_deny_absence(self, stmt: Dict):
 """Check if explicit deny is missing for sensitive resources"""
 resources = stmt.get('Resource', [])
 if any('sensitive' in r.lower() or 'admin' in r.lower() for r in resources):
 if stmt.get('Effect') == 'Allow':
 self.warnings.append(
 f"Statement {stmt['Sid']}: Consider explicit deny for sensitive resources"
 )

 def _calculate_score(self) -> int:
 """Calculate policy security score (0-100)"""
 score = 100
 score -= len(self.errors) * 20
 score -= len(self.warnings) * 10
 return max(0, score)

# JIT Access Manager
class JITAccessManager:
 """Just-In-Time access management for elevated privileges"""

 def __init__(self):
 self.active_requests = {}
 self.approval_required_for = ['admin', 'root', 'superuser']

 def request_access(self, user_id: str, role: str, reason: str, 
 duration_minutes: int = 30) -> Dict:
 """Request temporary elevated access"""
 if role not in self.approval_required_for:
 # Auto-approve for non-sensitive roles
 return self._grant_temporary_access(user_id, role, duration_minutes)

 # Create approval request for sensitive roles
 request_id = f"REQ_{user_id}_{role}_{len(self.active_requests)}"
 self.active_requests[request_id] = {
 'user_id': user_id,
 'role': role,
 'reason': reason,
 'duration_minutes': duration_minutes,
 'status': 'PENDING_APPROVAL',
 'requested_at': '2024-01-01T00:00:00Z'
 }
 return {
 'request_id': request_id,
 'status': 'PENDING_APPROVAL',
 'message': 'Approval required from security team'
 }

 def _grant_temporary_access(self, user_id: str, role: str, 
 duration_minutes: int) -> Dict:
 """Grant temporary access with automatic expiration"""
 access_token = f"JIT_{user_id}_{role}_{duration_minutes}m"
 return {
 'access_token': access_token,
 'role': role,
 'duration_minutes': duration_minutes,
 'expires_in': duration_minutes,
 'status': 'ACTIVE',
 'auto_revoke': True
 }

 def revoke_access(self, access_token: str) -> bool:
 """Immediately revoke JIT access (for incident response)"""
 print(f"Revoking access token: {access_token}")
 return True

